var createContactFromFullNameSchema = createContactInputSchema.transform((value, ctx) => {
  const parsed = parseFullName(value.fullName);
  if (!parsed.firstName) {
    ctx.addIssue({
      code: "custom",
      message: "Name is required",
      path: ["fullName"]
    });
    return z25.NEVER;
  }
  return {
    firstName: parsed.firstName,
    middleName: parsed.middleName,
    lastName: parsed.lastName
  };
});

