      const avatarChoice = resolveConflictChoice(
        conflictResolutions,
        "avatar"
      );
      const survivorHasAvatar = avatarChoice === "right" ? rightPerson.has_avatar : leftPerson.has_avatar;
      await client.from("people").update({ has_avatar: survivorHasAvatar }).eq("id", leftPersonId).eq("user_id", user.id);
      const contact = await loadEnrichedContact(
        client,
        user.id,
        leftPersonId,
        void 0,
        request.log
      );
      const response = {
        personId: leftPersonId,
        userId: user.id,
        mergedIntoPersonId: leftPersonId,
        mergedFromPersonId: rightPersonId,
        contact
      };
      return response;
