    facebook: has("facebook") ? enriched.facebook ?? void 0 : void 0,
    website: has("website") ? enriched.website ?? void 0 : void 0,
    whatsapp: has("whatsapp") ? enriched.whatsapp ?? void 0 : void 0,
    signal: has("signal") ? enriched.signal ?? void 0 : void 0,
    addresses: has("addresses") ? enriched.addresses?.filter((a2) => a2.addressFormatted).map((a2) => ({ formatted: a2.addressFormatted ?? void 0 })) : void 0,
