// src/routes/webhooks/polar.ts
import { z as z44 } from "zod";
import {
  validateEvent,
  WebhookVerificationError
} from "@polar-sh/sdk/webhooks";
var webhookAckResponseSchema = z44.object({
  received: z44.boolean()
});
async function findUserIdByEmail(email) {
  const admin2 = createAdminClient();
  const { data, error } = await admin2.rpc(
    "get_user_id_by_email",
    {
      p_email: email
    }
  );
  if (error) {
    throw new Error(`get_user_id_by_email RPC failed: ${error.message}`);
  }
  return data ?? null;
}
async function upsertSubscription(userId, polarCustomerId, polarSubscriptionId, status, currentPeriodStart, currentPeriodEnd, cancelAtPeriodEnd) {
  const admin2 = createAdminClient();
  const { error } = await admin2.from("subscriptions").upsert(
    {
      user_id: userId,
      polar_customer_id: polarCustomerId,
      polar_subscription_id: polarSubscriptionId,
      status,
      current_period_start: currentPeriodStart ? currentPeriodStart.toISOString() : null,
      current_period_end: currentPeriodEnd ? currentPeriodEnd.toISOString() : null,
      cancel_at_period_end: cancelAtPeriodEnd
    },
    { onConflict: "user_id" }
  );
  if (error) {
    throw new Error(`Failed to upsert subscription: ${error.message}`);
  }
}
async function storePendingSubscription(email, polarCustomerId, polarSubscriptionId, status, currentPeriodEnd, cancelAtPeriodEnd) {
  const admin2 = createAdminClient();
  const { error } = await admin2.from("pending_subscriptions").upsert(
    {
      email,
      polar_customer_id: polarCustomerId,
      polar_subscription_id: polarSubscriptionId,
      status,
      current_period_end: currentPeriodEnd ? currentPeriodEnd.toISOString() : null,
      cancel_at_period_end: cancelAtPeriodEnd
    },
    { onConflict: "email" }
  );
  if (error) {
    throw new Error(`Failed to store pending subscription: ${error.message}`);
  }
}
function mapStatus(polarStatus, cancelAtPeriodEnd) {
  switch (polarStatus) {
    case "active":
      return cancelAtPeriodEnd ? "canceling" : "active";
    case "trialing":
      return "active";
    case "canceled":
      return "canceled";
    case "incomplete_expired":
      return "canceled";
    case "past_due":
    case "incomplete":
    case "unpaid":
      return "past_due";
    default:
      return "past_due";
  }
}
async function polarWebhookRoutes(fastify) {
  fastify.addHook("onRoute", (routeOptions) => {
    if (routeOptions.schema) {
      routeOptions.schema.tags = ["Webhooks"];
    }
    applyOpenApiRouteMeta(routeOptions, { area: "internal" });
  });
  fastify.addContentTypeParser(
    "application/json",
    { parseAs: "buffer" },
    (_req, body, done) => {
      done(null, body);
    }
  );
  fastify.post(
    "/",
    {
      config: { rateLimit: false },
      schema: {
        description: "Receive and process a Polar subscription lifecycle webhook event.",
        response: withOkResponse(webhookAckResponseSchema, "Webhook acknowledged")
      }
    },
    async (request, reply) => {
      const secret = fastify.config.PRIVATE_POLAR_WEBHOOK_SECRET;
      if (!secret) {
        request.log.warn(
          "PRIVATE_POLAR_WEBHOOK_SECRET is not configured \u2014 rejecting webhook"
        );
        return reply.status(500).send({ error: "Webhook not configured" });
      }
      const rawBody = request.body;
      const headers = {};
      for (const [key, value] of Object.entries(request.headers)) {
        if (typeof value === "string") {
          headers[key] = value;
        }
      }
      let event;
      try {
        event = validateEvent(rawBody, headers, secret);
      } catch (err) {
        if (err instanceof WebhookVerificationError) {
          request.log.warn(
            { reason: err.message },
            "polar-webhook: invalid signature"
          );
          return reply.status(400).send({ error: "Invalid webhook signature" });
        }
        throw err;
      }
      request.log.info({ type: event.type }, "polar-webhook: received event");
      if (event.type !== "subscription.created" && event.type !== "subscription.updated" && event.type !== "subscription.revoked" && event.type !== "subscription.active" && event.type !== "subscription.canceled" && event.type !== "subscription.uncanceled" && event.type !== "subscription.past_due") {
        return reply.status(200).send({ received: true });
      }
      const sub = event.data;
      const email = sub.customer.email;
      if (!email) {
        request.log.warn(
          { type: event.type },
          "polar-webhook: no customer email in payload \u2014 skipping"
        );
        return reply.status(200).send({ received: true });
      }
      const status = event.type === "subscription.revoked" ? "revoked" : mapStatus(sub.status, sub.cancelAtPeriodEnd);
      const currentPeriodStart = event.type === "subscription.revoked" ? null : sub.currentPeriodStart ?? null;
      const currentPeriodEnd = event.type === "subscription.revoked" ? null : sub.currentPeriodEnd ?? null;
      const externalId = sub.externalCustomerId;
      const isValidUuid = externalId != null && /^[0-9a-f-]{36}$/i.test(externalId);
      let userId = isValidUuid ? externalId : null;
      if (!userId) {
        try {
          userId = await findUserIdByEmail(email);
        } catch (err) {
          request.log.error({ err, email }, "polar-webhook: user lookup failed");
          return reply.status(500).send({ error: "User lookup failed" });
        }
      }
      if (!userId) {
        try {
          await storePendingSubscription(
            email,
            sub.customer.id,
            sub.id,
            status,
            currentPeriodEnd,
            sub.cancelAtPeriodEnd
          );
          request.log.info(
            { type: event.type, email },
            "polar-webhook: no Bondery user found \u2014 stored in pending_subscriptions"
          );
        } catch (err) {
          request.log.error(
            { err, email },
            "polar-webhook: failed to store pending subscription"
          );
          return reply.status(500).send({ error: "Failed to store pending subscription" });
        }
        return reply.status(200).send({ received: true });
      }
      try {
        await upsertSubscription(
          userId,
          sub.customer.id,
          sub.id,
          status,
          currentPeriodStart,
          currentPeriodEnd,
          sub.cancelAtPeriodEnd
        );
      } catch (err) {
        request.log.error(
          { err, userId, type: event.type },
          "polar-webhook: upsert failed"
        );
        return reply.status(500).send({ error: "Failed to process webhook" });
      }
      request.log.info(
        { userId, status, type: event.type },
        "polar-webhook: subscription updated"
      );
      return reply.status(200).send({ received: true });
    }
  );
}

// src/routes/subscriptions/sync.ts
var subscriptionSyncResponseSchema = z45.union([
  z45.object({
    synced: z45.literal(true),
    source: z45.enum(["pending", "polar_api"])
  }),
  z45.object({
    synced: z45.literal(false),
    reason: z45.string()
  })
]);
async function subscriptionSyncRoutes(fastify) {
  fastify.addHook("onRoute", (routeOptions) => {
    if (routeOptions.schema) {
      routeOptions.schema.tags = ["Subscriptions"];
    }
    applyOpenApiRouteMeta(routeOptions, { area: "session" });
  });
  fastify.addHook("onRequest", fastify.auth([fastify.verifySession]));
  fastify.post(
    "/",
    {
      schema: {
        description: "Sync subscription state from Polar for the authenticated user.",
        response: withOkResponse(subscriptionSyncResponseSchema, "Subscription sync result")
      }
    },
    async (request, reply) => {
      const { client, user } = getAuth(request);
      const { data: existing } = await client.from("subscriptions").select("status").eq("user_id", user.id).single();
      if (existing?.status === "active" || existing?.status === "canceling") {
        request.log.info(
          { userId: user.id },
          "subscription-sync: already active, skipping"
        );
        return reply.status(200).send({ synced: false, reason: "already_active" });
      }
      const admin2 = createAdminClient();
      const email = user.email;
      if (email) {
        const { data: pending } = await admin2.from("pending_subscriptions").select("*").eq("email", email).single();
        if (pending) {
          try {
            await upsertSubscription(
              user.id,
              pending.polar_customer_id,
              pending.polar_subscription_id,
              pending.status,
              null,
              pending.current_period_end ? new Date(pending.current_period_end) : null,
              pending.cancel_at_period_end
            );
            await admin2.from("pending_subscriptions").delete().eq("email", email);
            request.log.info(
              { userId: user.id, email },
              "subscription-sync: claimed from pending_subscriptions"
            );
            return reply.status(200).send({ synced: true, source: "pending" });
          } catch (err) {
            request.log.error(
              { err, userId: user.id },
              "subscription-sync: failed to claim pending"
            );
            return reply.status(503).send({ error: "Failed to sync subscription" });
          }
        }
      }
      let polar;
      try {
        polar = getPolarClient();
      } catch {
        request.log.warn(
          { userId: user.id },
          "subscription-sync: Polar not configured"
        );
        return reply.status(200).send({ synced: false, reason: "polar_not_configured" });
      }
      try {
        let polarCustomer;
        try {
          polarCustomer = await polar.customers.getExternal({
            externalId: user.id
          });
        } catch {
          request.log.info(
            { userId: user.id },
            "subscription-sync: no Polar customer found"
          );
          return reply.status(200).send({ synced: false, reason: "no_polar_customer" });
        }
        const subscriptions = await polar.subscriptions.list({
          customerId: polarCustomer.id
        });
        const activeSub = subscriptions.result.items.find(
          (s) => s.status === "active" || s.status === "canceled" && s.cancelAtPeriodEnd
        ) ?? subscriptions.result.items[0];
        if (!activeSub) {
          request.log.info(
            { userId: user.id, polarCustomerId: polarCustomer.id },
            "subscription-sync: no active Polar subscription found"
          );
          return reply.status(200).send({ synced: false, reason: "no_active_subscription" });
        }
        const status = mapStatus(activeSub.status, activeSub.cancelAtPeriodEnd);
        const currentPeriodStart = activeSub.currentPeriodStart ?? null;
        const currentPeriodEnd = activeSub.currentPeriodEnd ?? null;
        await upsertSubscription(
          user.id,
          polarCustomer.id,
          activeSub.id,
          status,
          currentPeriodStart,
          currentPeriodEnd,
          activeSub.cancelAtPeriodEnd
        );
        request.log.info(
          { userId: user.id, status },
          "subscription-sync: synced from Polar API"
        );
        return reply.status(200).send({ synced: true, source: "polar_api" });
      } catch (err) {
        request.log.error(
          { err, userId: user.id },
          "subscription-sync: Polar API error"
        );
        return reply.status(503).send({ error: "Failed to sync subscription from Polar" });
      }
    }
  );
}

// src/routes/geocode/index.ts
var geocodeRoutes = async (fastify) => {
  fastify.addHook("onRoute", (routeOptions) => {
    if (routeOptions.schema) {
      routeOptions.schema.tags = ["Geocode"];
    }
    applyOpenApiRouteMeta(routeOptions, { area: "integration" });
  });
  registerApiKeyProtectedHooks(fastify);
  fastify.get(
    "/suggest",
    {
      config: { rateLimit: GEOCODE_TIER },
      schema: {
        description: "Returns mapped address/place autocomplete entries from Mapy.com",
        querystring: geocodeSuggestQuerySchema,
        response: withOkResponse(
          geocodeSuggestResponseWireSchema,
          "Address suggestions"
        )
      }
    },
    async (request, reply) => {
      const { search, mode = "address" } = request.query;
      const mapsKey = fastify.config.PRIVATE_MAPS_KEY;
      const mapsUrl = fastify.config.PUBLIC_MAPS_URL;
      if (!mapsKey) {
        request.log.warn({ query: search.trim(), mode }, "Geocode suggest skipped: missing maps API key");
        return reply.send({ addresses: [] });
      }
      const upstream = new URL(`${mapsUrl}/v1/suggest`);
      upstream.searchParams.set("apikey", mapsKey);
      upstream.searchParams.set("query", search.trim());
      upstream.searchParams.set("lang", "en");
      upstream.searchParams.set("limit", "8");
      upstream.searchParams.set(
        "type",
        mode === "place" ? "regional.municipality" : "regional.address,regional.street,regional.municipality"
      );
      try {
        const response = await fetch(upstream.toString(), {
          method: "GET",
          headers: { Accept: "application/json" }
        });
        if (!response.ok) {
          request.log.warn(
            { query: search.trim(), mode, status: response.status },
            "Geocode suggest upstream request failed"
          );
          return reply.send({ addresses: [] });
        }
        const payload = await response.json();
        const rawResults = Array.isArray(payload?.items) ? payload.items : Array.isArray(payload?.result) ? payload.result : Array.isArray(payload?.results) ? payload.results : [];
        const addresses = parseMapSuggestions(rawResults).map(
          (item) => mapSuggestionToContactAddress(item, { type: "home" })
        );
        return reply.send({ addresses });
      } catch (error) {
        request.log.error({ err: error, query: search.trim(), mode }, "Geocode suggest handler error");
        return reply.send({ addresses: [] });
      }
    }
  );
  fastify.get(
    "/timezone",
    {
      config: { rateLimit: GEOCODE_TIER },
      schema: {
        description: "Returns the IANA timezone for a latitude/longitude pair from Mapy.com",
        querystring: geocodeTimezoneQuerySchema,
        response: withOkResponse(
          geocodeTimezoneResponseWireSchema,
          "Timezone lookup result"
        )
      }
    },
    async (request, reply) => {
      const { lat, lon } = request.query;
      try {
        const timezone = await getTimezoneForCoordinates(lat, lon);
        return reply.send({ timezone });
      } catch (error) {
        request.log.error({ err: error, lat, lon }, "Geocode timezone handler error");
        return reply.send({ timezone: null });
      }
    }
  );
};

